import java.util.Arrays;
import java.util.HashMap;
import java.util.HashSet;

class Solution {
    public static boolean solve(String x) {
        int left = 0, right = x.length() - 1;
        while (left < right) {
            if (x.charAt(left) != x.charAt(right)) return false;
            left++;
            right--;
        }
        return true;
    }
}
